<script lang="ts">
	import { twMerge } from 'tailwind-merge';
	import { getCalendarWeeks, todayStr, parseDate } from './utils.js';
	import CalendarHeader from './CalendarHeader.svelte';
	import CalendarGrid from './CalendarGrid.svelte';
	import type { CalendarEvent, RestDayEntry } from './types.js';

	const todayDate = parseDate(todayStr());

	let {
		year = $bindable(todayDate.getFullYear()),
		month = $bindable(todayDate.getMonth()), // 0-based
		events = [],
		viewOnly = false,
		workdays = '12345',
		extraRest = [],
		extraWork = [],
		firstDayOfWeek = 1,
		wrapMultiDay = true,
		allowCreate = false,
		onEventMove,
		onEventResize,
		onEventCreate,
		onEventClick,
		class: classes = '',
	}: {
		year?: number;
		month?: number;
		events?: CalendarEvent[];
		viewOnly?: boolean;
		workdays?: string;
		extraRest?: RestDayEntry[];
		extraWork?: string[];
		firstDayOfWeek?: 0 | 1;
		wrapMultiDay?: boolean;
		allowCreate?: boolean;
		onEventMove?: (id: string, newStart: string, newEnd: string) => void;
		onEventResize?: (id: string, newStart: string, newEnd: string) => void;
		onEventCreate?: (date: string) => void;
		onEventClick?: (id: string) => void;
		class?: string;
	} = $props();

	const weeks = $derived(getCalendarWeeks(year, month, firstDayOfWeek));
</script>

<div class={twMerge('bg-surface flex flex-col', classes)}>
	<CalendarHeader {firstDayOfWeek} />
	<CalendarGrid
		{weeks}
		currentMonth={month}
		{events}
		{viewOnly}
		{workdays}
		{extraRest}
		{extraWork}
		{wrapMultiDay}
		{allowCreate}
		{onEventMove}
		{onEventResize}
		{onEventCreate}
		{onEventClick}
	/>
</div>
